{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>HR 담당자를 위한 AX 실무 집중과정</title>
<link href="https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Noto+Sans+KR:wght@300;400;500;700;900&family=Space+Mono:wght@400;700&display=swap" rel="stylesheet">
<style>
  :root {
    --bg: #080810;
    --bg2: #0d0d1a;
    --surface: #12121f;
    --border: rgba(255,255,255,0.07);
    --accent: #6C63FF;
    --accent2: #00D4FF;
    --accent3: #FF6B6B;
    --text: #F0F0F8;
    --muted: #7070A0;
    --tag-bg: rgba(108,99,255,0.12);
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: 'Noto Sans KR', sans-serif;
    overflow-x: hidden;
    line-height: 1.6;
  }

  /* ── GRAIN OVERLAY ── */
  body::before {
    content: '';
    position: fixed; inset: 0;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.04'/%3E%3C/svg%3E");
    pointer-events: none; z-index: 999; opacity: 0.4;
  }

  /* ── HERO ── */
  .hero {
    min-height: 100vh;
    display: flex; flex-direction: column; justify-content: center;
    padding: 80px 60px 60px;
    position: relative;
    overflow: hidden;
  }

  .hero::after {
    content: '';
    position: absolute;
    top: -200px; right: -200px;
    width: 700px; height: 700px;
    background: radial-gradient(circle, rgba(108,99,255,0.18) 0%, transparent 70%);
    pointer-events: none;
  }

  .hero-eyebrow {
    display: flex; align-items: center; gap: 12px;
    margin-bottom: 32px;
    animation: fadeUp 0.8s ease both;
  }

  .badge {
    font-family: 'Space Mono', monospace;
    font-size: 11px;
    letter-spacing: 0.15em;
    padding: 5px 14px;
    border: 1px solid var(--accent);
    color: var(--accent);
    border-radius: 2px;
    text-transform: uppercase;
  }

  .badge-outline {
    font-family: 'Space Mono', monospace;
    font-size: 11px;
    letter-spacing: 0.15em;
    padding: 5px 14px;
    border: 1px solid var(--border);
    color: var(--muted);
    border-radius: 2px;
    text-transform: uppercase;
  }

  .hero-title {
    font-family: 'Bebas Neue', sans-serif;
    font-size: clamp(52px, 9vw, 110px);
    line-height: 0.95;
    letter-spacing: 0.01em;
    animation: fadeUp 0.8s 0.1s ease both;
    position: relative;
  }

  .hero-title .line-ko {
    font-family: 'Noto Sans KR', sans-serif;
    font-weight: 900;
    font-size: clamp(36px, 5.5vw, 72px);
    letter-spacing: -0.02em;
    display: block;
  }

  .hero-title .accent-word {
    color: var(--accent);
  }

  .hero-sub {
    margin-top: 28px;
    font-size: 16px;
    color: var(--muted);
    max-width: 560px;
    line-height: 1.8;
    animation: fadeUp 0.8s 0.2s ease both;
  }

  .hero-tools {
    display: flex; gap: 10px; margin-top: 40px; flex-wrap: wrap;
    animation: fadeUp 0.8s 0.3s ease both;
  }

  .tool-chip {
    display: flex; align-items: center; gap: 8px;
    padding: 10px 20px;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 4px;
    font-size: 13px; font-weight: 500;
    transition: border-color 0.2s, transform 0.2s;
    cursor: default;
  }
  .tool-chip:hover { border-color: var(--accent); transform: translateY(-2px); }

  .tool-dot { width: 7px; height: 7px; border-radius: 50%; }
  .dot-purple { background: var(--accent); }
  .dot-cyan { background: var(--accent2); }
  .dot-red { background: var(--accent3); }

  .hero-scroll {
    position: absolute; bottom: 36px; left: 60px;
    font-family: 'Space Mono', monospace;
    font-size: 10px; letter-spacing: 0.2em;
    color: var(--muted); text-transform: uppercase;
    display: flex; align-items: center; gap: 12px;
    animation: fadeUp 0.8s 0.5s ease both;
  }
  .hero-scroll::before {
    content: '';
    display: block; width: 40px; height: 1px;
    background: var(--muted);
  }

  /* ── DIVIDER ── */
  .divider {
    height: 1px; background: var(--border);
    margin: 0 60px;
  }

  /* ── SECTION ── */
  section { padding: 80px 60px; }

  .section-label {
    font-family: 'Space Mono', monospace;
    font-size: 10px; letter-spacing: 0.25em;
    color: var(--accent); text-transform: uppercase;
    margin-bottom: 16px;
    display: flex; align-items: center; gap: 10px;
  }
  .section-label::before {
    content: ''; display: block;
    width: 24px; height: 1px; background: var(--accent);
  }

  .section-title {
    font-size: clamp(26px, 4vw, 42px);
    font-weight: 800;
    letter-spacing: -0.02em;
    line-height: 1.2;
    margin-bottom: 48px;
  }

  /* ── WHY ── */
  .why-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: 1px;
    background: var(--border);
    border: 1px solid var(--border);
  }

  .why-card {
    background: var(--bg);
    padding: 36px 32px;
    transition: background 0.2s;
    position: relative; overflow: hidden;
  }
  .why-card::before {
    content: '';
    position: absolute; top: 0; left: 0; right: 0;
    height: 2px; background: transparent;
    transition: background 0.2s;
  }
  .why-card:hover { background: var(--surface); }
  .why-card:hover::before { background: var(--accent); }

  .why-num {
    font-family: 'Bebas Neue', sans-serif;
    font-size: 64px; line-height: 1;
    color: rgba(108,99,255,0.15);
    margin-bottom: 12px;
  }

  .why-card h3 { font-size: 16px; font-weight: 700; margin-bottom: 8px; }
  .why-card p { font-size: 13px; color: var(--muted); line-height: 1.7; }

  /* ── CURRICULUM ── */
  .curriculum { background: var(--bg2); }

  .curriculum-table {
    width: 100%; border-collapse: collapse;
    font-size: 14px;
  }

  .curriculum-table thead tr {
    border-bottom: 1px solid var(--border);
  }
  .curriculum-table th {
    font-family: 'Space Mono', monospace;
    font-size: 10px; letter-spacing: 0.15em;
    color: var(--muted); text-transform: uppercase;
    padding: 12px 16px; text-align: left; font-weight: 400;
  }

  .curriculum-table tbody tr {
    border-bottom: 1px solid var(--border);
    transition: background 0.15s;
  }
  .curriculum-table tbody tr:hover { background: var(--surface); }

  .curriculum-table td { padding: 20px 16px; vertical-align: top; }

  .time-cell {
    font-family: 'Space Mono', monospace;
    font-size: 12px; color: var(--muted);
    white-space: nowrap; min-width: 110px;
  }

  .session-block {
    display: inline-block;
    padding: 3px 10px; border-radius: 2px;
    font-size: 10px; font-weight: 700;
    letter-spacing: 0.1em; text-transform: uppercase;
    margin-bottom: 6px;
  }
  .session-am { background: rgba(108,99,255,0.15); color: var(--accent); }
  .session-pm { background: rgba(0,212,255,0.12); color: var(--accent2); }
  .session-break { background: rgba(255,255,255,0.05); color: var(--muted); }
  .session-wrap { background: rgba(255,107,107,0.12); color: var(--accent3); }

  .topic-title { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
  .topic-desc { font-size: 12px; color: var(--muted); }

  .tool-tag {
    display: inline-block;
    padding: 2px 8px; margin: 2px;
    background: var(--tag-bg);
    border: 1px solid rgba(108,99,255,0.2);
    border-radius: 2px;
    font-size: 11px; color: var(--accent);
    font-family: 'Space Mono', monospace;
  }

  /* ── OUTCOMES ── */
  .outcomes-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: 24px;
  }

  .outcome-card {
    background: var(--surface);
    border: 1px solid var(--border);
    padding: 32px;
    border-radius: 4px;
    position: relative;
    transition: transform 0.2s, border-color 0.2s;
  }
  .outcome-card:hover { transform: translateY(-4px); border-color: rgba(108,99,255,0.4); }

  .outcome-icon {
    width: 44px; height: 44px;
    background: var(--tag-bg);
    border: 1px solid rgba(108,99,255,0.25);
    border-radius: 4px;
    display: flex; align-items: center; justify-content: center;
    font-size: 20px;
    margin-bottom: 20px;
  }

  .outcome-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 8px; }
  .outcome-card p { font-size: 13px; color: var(--muted); line-height: 1.7; }

  /* ── TOOLS DEEP DIVE ── */
  .tools-section { background: var(--bg2); }

  .tools-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1px;
    background: var(--border);
    border: 1px solid var(--border);
  }

  .tool-card {
    background: var(--bg2);
    padding: 40px 36px;
    transition: background 0.2s;
  }
  .tool-card:hover { background: var(--surface); }

  .tool-card-num {
    font-family: 'Bebas Neue', sans-serif;
    font-size: 13px; letter-spacing: 0.2em;
    color: var(--muted); margin-bottom: 20px;
  }

  .tool-card-name {
    font-size: 22px; font-weight: 800;
    margin-bottom: 6px; letter-spacing: -0.01em;
  }
  .tool-card-category {
    font-size: 12px; color: var(--muted); margin-bottom: 20px;
    font-family: 'Space Mono', monospace;
  }

  .tool-card-bar {
    height: 2px;
    background: var(--border);
    margin-bottom: 24px;
    position: relative; overflow: hidden;
  }
  .tool-card-bar-fill {
    position: absolute; left: 0; top: 0; height: 100%;
    background: var(--accent);
    animation: barGrow 1.2s 0.5s ease both;
    transform-origin: left;
  }

  .tool-feature {
    display: flex; gap: 10px;
    margin-bottom: 10px; font-size: 13px;
  }
  .tool-feature::before {
    content: '→';
    color: var(--accent); flex-shrink: 0;
    font-family: 'Space Mono', monospace;
    font-size: 11px; margin-top: 2px;
  }

  /* ── CTA / INFO ── */
  .info-section {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0;
  }

  .info-left {
    padding: 80px 60px;
    background: var(--accent);
    color: white;
    display: flex; flex-direction: column; justify-content: center;
  }

  .info-left .big-label {
    font-family: 'Bebas Neue', sans-serif;
    font-size: 80px; line-height: 0.9;
    margin-bottom: 24px;
    opacity: 0.15;
    position: absolute;
    right: 20px; top: 20px;
  }

  .info-right {
    padding: 80px 60px;
    background: var(--surface);
    display: flex; flex-direction: column; justify-content: center;
  }

  .info-item {
    display: flex; gap: 16px;
    margin-bottom: 24px; align-items: flex-start;
  }

  .info-icon {
    width: 36px; height: 36px; flex-shrink: 0;
    background: var(--tag-bg);
    border: 1px solid rgba(108,99,255,0.2);
    border-radius: 3px;
    display: flex; align-items: center; justify-content: center;
    font-size: 16px;
  }

  .info-label {
    font-family: 'Space Mono', monospace;
    font-size: 10px; color: var(--muted);
    letter-spacing: 0.15em; text-transform: uppercase;
    margin-bottom: 3px;
  }
  .info-value { font-size: 14px; font-weight: 600; }

  .cta-title {
    font-size: 32px; font-weight: 800;
    letter-spacing: -0.02em;
    margin-bottom: 16px; line-height: 1.2;
  }
  .cta-sub { font-size: 14px; opacity: 0.8; line-height: 1.7; }

  /* ── FOOTER ── */
  footer {
    padding: 32px 60px;
    border-top: 1px solid var(--border);
    display: flex; justify-content: space-between; align-items: center;
    flex-wrap: wrap; gap: 12px;
  }
  .footer-logo {
    font-family: 'Space Mono', monospace;
    font-size: 12px; color: var(--muted);
    letter-spacing: 0.1em;
  }
  .footer-note {
    font-size: 12px; color: var(--muted);
  }

  /* ── ANIMATIONS ── */
  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(20px); }
    to   { opacity: 1; transform: translateY(0); }
  }
  @keyframes barGrow {
    from { transform: scaleX(0); }
    to   { transform: scaleX(1); }
  }

  /* ── RESPONSIVE ── */
  @media (max-width: 768px) {
    .hero, section { padding: 60px 24px; }
    .divider { margin: 0 24px; }
    .tools-grid { grid-template-columns: 1fr; }
    .info-section { grid-template-columns: 1fr; }
    footer { padding: 24px; }
    .hero-scroll { left: 24px; }
  }
</style>
</head>
