<script>
const TOTAL_STEPS = 8;
let completedSteps = new Set();

function startLab() {
  document.getElementById('hero').style.display = 'none';
  document.getElementById('steps-container').style.display = 'block';
  // reveal step 1
  setTimeout(() => {
    const s = document.getElementById('step-1');
    s.classList.remove('locked');
    s.classList.add('visible');
    updateNav();
    updateProgress();
  }, 100);
  window.scrollTo({top: 0, behavior:'smooth'});
}

function toggleStep(n) {
  const body = document.getElementById(`body-${n}`);
  if (!body) return;
  body.classList.toggle('open');
}

function completeStep(n) {
  completedSteps.add(n);
  // mark done
  const card = document.getElementById(`card-${n}`);
  card.classList.remove('active');
  card.classList.add('done');
  const body = document.getElementById(`body-${n}`);
  body.classList.remove('open');
  const btn = document.getElementById(`btn-${n}`);
  if(btn){btn.classList.add('done'); btn.textContent = '✓ 완료';}
  // connector
  const connline = document.getElementById(`connline-${n}`);
  if(connline) connline.classList.add('done');
  // unlock next
  const next = n + 1;
  const nextBlock = document.getElementById(`step-${next}`);
  if(nextBlock) {
    nextBlock.classList.remove('locked');
    nextBlock.classList.add('visible');
    // open next body
    const nextCard = document.getElementById(`card-${next}`);
    if(nextCard) nextCard.classList.add('active');
    const nextBody = document.getElementById(`body-${next}`);
    if(nextBody) nextBody.classList.add('open');
    setTimeout(() => {
      nextBlock.scrollIntoView({behavior:'smooth', block:'start'});
    }, 300);
  } else if (n === TOTAL_STEPS) {
    showCompletion();
  }
  updateNav();
  updateProgress();
}

function toggleCheck(el) {
  el.classList.toggle('checked');
}

function copyPrompt(btn, id) {
  const el = document.getElementById(id);
  if(!el) return;
  // get plain text (strip HTML)
  const tmp = document.createElement('div');
  tmp.innerHTML = el.innerHTML;
  const text = tmp.innerText || tmp.textContent;
  navigator.clipboard.writeText(text).then(() => {
    btn.classList.add('copied');
    btn.innerHTML = '<span>복사됨</span> ✓';
    setTimeout(() => {
      btn.classList.remove('copied');
      btn.innerHTML = '<span>복사</span> 📋';
    }, 2000);
  }).catch(() => {
    // fallback
    const ta = document.createElement('textarea');
    ta.value = text;
    document.body.appendChild(ta);
    ta.select();
    document.execCommand('copy');
    document.body.removeChild(ta);
    btn.innerHTML = '<span>복사됨</span> ✓';
    setTimeout(() => { btn.innerHTML = '<span>복사</span> 📋'; }, 2000);
  });
}

function updateNav() {
  const container = document.getElementById('step-dots');
  container.innerHTML = '';
  for(let i = 1; i <= TOTAL_STEPS; i++) {
    const dot = document.createElement('div');
    dot.className = 'nav-step-dot';
    if(completedSteps.has(i)) dot.classList.add('done');
    else if(i === getActiveStep()) dot.classList.add('active');
    dot.onclick = () => {
      const el = document.getElementById(`step-${i}`);
      if(el && !el.classList.contains('locked'))
        el.scrollIntoView({behavior:'smooth'});
    };
    container.appendChild(dot);
  }
}

function getActiveStep() {
  for(let i = 1; i <= TOTAL_STEPS; i++) {
    if(!completedSteps.has(i)) return i;
  }
  return TOTAL_STEPS;
}

function updateProgress() {
  const pct = (completedSteps.size / TOTAL_STEPS) * 100;
  document.getElementById('progress-bar').style.width = pct + '%';
}

function showCompletion() {
  document.getElementById('steps-container').style.display = 'none';
  const comp = document.getElementById('completion');
  comp.classList.add('show');
  comp.scrollIntoView({behavior:'smooth'});
}

// init dots
updateNav();
</script>
</body>
</html>
