.output-emoji{font-size:18px;flex-shrink:0;}
.output-text{font-size:12px;color:var(--muted2);line-height:1.6;}
.output-text strong{color:var(--text);display:block;font-size:13px;margin-bottom:2px;}
.complete-btn{
  width:100%;margin-top:24px;padding:14px 24px;
  border:1px solid var(--accent-mid);border-radius:6px;background:var(--accent-soft);
  color:var(--accent);font-family:'Noto Sans KR',sans-serif;
  font-size:13px;font-weight:700;cursor:pointer;transition:all .25s;
  display:flex;align-items:center;justify-content:center;gap:10px;letter-spacing:.02em;
}
.complete-btn:hover{background:var(--accent);color:#000;box-shadow:0 4px 20px rgba(0,194,203,.25);transform:translateY(-1px);}
.complete-btn.done{background:var(--green-soft);border-color:rgba(0,212,138,.3);color:var(--green);cursor:default;}
.lab-divider{display:flex;align-items:center;gap:16px;padding:32px 0;}
.lab-divider-line{flex:1;height:1px;background:var(--border);}
.lab-divider-text{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.2em;color:var(--muted);text-transform:uppercase;white-space:nowrap;}
.two-col{display:grid;grid-template-columns:1fr 1fr;gap:16px;}

/* ── FLOW BUILDER (interactive) ── */
.flow-builder{
  background:var(--bg);border:1px solid var(--accent-mid);
  border-radius:8px;overflow:hidden;
}
.flow-builder-bar{
  padding:10px 16px;border-bottom:1px solid var(--border);
  display:flex;align-items:center;justify-content:space-between;
  background:var(--accent-soft);
}
.flow-builder-title{
  font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.15em;
  color:var(--accent);text-transform:uppercase;
}
.flow-canvas{padding:20px;min-height:160px;}
.flow-nodes{display:flex;align-items:center;flex-wrap:wrap;gap:0;}
.flow-node{
  display:flex;align-items:center;gap:0;
  animation:nodeAppear .3s ease both;
}
@keyframes nodeAppear{from{opacity:0;transform:scale(.8);}to{opacity:1;transform:scale(1);}}
.fnode{
  padding:8px 14px;border-radius:4px;font-size:11px;font-weight:600;
  cursor:pointer;transition:all .2s;user-select:none;position:relative;
  white-space:nowrap;
}
.fnode-normal{background:var(--accent-soft);border:1px solid var(--accent-mid);color:var(--accent);}
.fnode-bottle{background:rgba(255,107,107,.12);border:1px solid rgba(255,107,107,.25);color:var(--red);}
.fnode-ai{background:rgba(0,212,138,.1);border:1px solid rgba(0,212,138,.22);color:var(--green);}
.farrow{font-family:'Space Mono',monospace;font-size:12px;color:var(--muted);margin:0 4px;flex-shrink:0;}
.node-add-btn{
  padding:6px 12px;border-radius:4px;font-size:11px;font-weight:700;
  background:transparent;border:1px dashed var(--muted);color:var(--muted);
  cursor:pointer;transition:all .2s;margin-left:4px;
}
.node-add-btn:hover{border-color:var(--accent);color:var(--accent);}
.flow-controls{
  padding:12px 16px;border-top:1px solid var(--border);
  display:flex;align-items:center;gap:8px;flex-wrap:wrap;
}
.ctrl-label{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.12em;color:var(--muted);text-transform:uppercase;margin-right:4px;}
.type-btn{
  padding:5px 10px;border-radius:3px;font-size:10px;font-weight:700;
  cursor:pointer;border:1px solid;transition:all .15s;
}
.type-btn-normal{background:var(--accent-soft);border-color:var(--accent-mid);color:var(--accent);}
.type-btn-bottle{background:rgba(255,107,107,.1);border-color:rgba(255,107,107,.25);color:var(--red);}
.type-btn-ai{background:rgba(0,212,138,.1);border-color:rgba(0,212,138,.22);color:var(--green);}
.type-btn.selected{transform:scale(1.05);box-shadow:0 0 8px rgba(0,0,0,.3);}
.node-input{
  background:var(--surface);border:1px solid var(--border);border-radius:4px;
  padding:5px 10px;font-family:'Noto Sans KR',sans-serif;font-size:11px;
  color:var(--text);outline:none;width:120px;transition:border-color .2s;
}
.node-input:focus{border-color:var(--accent-mid);}
.add-node-submit{
  padding:5px 14px;border-radius:3px;background:var(--accent);border:none;
  font-family:'Noto Sans KR',sans-serif;font-size:11px;font-weight:700;
  color:#000;cursor:pointer;transition:all .2s;
}
.add-node-submit:hover{background:var(--accent-bright);}
.flow-legend{
  padding:10px 16px;border-top:1px solid var(--border);
  display:flex;gap:16px;flex-wrap:wrap;
}
.fleg{display:flex;align-items:center;gap:6px;font-size:10px;color:var(--muted2);}
.fleg-dot{width:8px;height:8px;border-radius:2px;}

/* TCAR builder */
.tcar-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
.tcar-block{padding:16px;border-radius:6px;border:1px solid;}
.tcar-label{
  font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.15em;
  text-transform:uppercase;margin-bottom:8px;font-weight:700;
}
.tcar-input{
  width:100%;background:var(--bg);border:1px solid var(--border);
  border-radius:4px;padding:8px 10px;
  font-family:'Noto Sans KR',sans-serif;font-size:12px;color:var(--text);
  outline:none;resize:vertical;min-height:60px;transition:border-color .2s;
}
.tcar-input:focus{border-color:var(--accent-mid);}
.tcar-t{background:rgba(0,194,203,.06);border-color:var(--accent-mid);}
.tcar-t .tcar-label{color:var(--accent);}
.tcar-c{background:var(--yellow-soft);border-color:rgba(255,184,0,.25);}
.tcar-c .tcar-label{color:var(--yellow);}
.tcar-a{background:var(--green-soft);border-color:rgba(0,212,138,.22);}
.tcar-a .tcar-label{color:var(--green);}
.tcar-r{background:var(--purple-soft);border-color:rgba(156,120,255,.22);}
.tcar-r .tcar-label{color:var(--purple);}
.tcar-export-btn{
  margin-top:12px;width:100%;padding:10px;
  background:var(--accent-soft);border:1px solid var(--accent-mid);
  border-radius:4px;color:var(--accent);font-family:'Noto Sans KR',sans-serif;
  font-size:12px;font-weight:700;cursor:pointer;transition:all .2s;
}
.tcar-export-btn:hover{background:var(--accent);color:#000;}
.tcar-preview{
  display:none;margin-top:12px;padding:14px;
  background:var(--bg);border:1px solid var(--border);border-radius:6px;
  font-size:12px;color:var(--muted2);line-height:1.7;
}
.tcar-preview.show{display:block;}
.tcar-preview strong{color:var(--text);}

.completion{display:none;text-align:center;padding:80px 48px;}
.completion.show{display:block;}
.completion-glow{
  width:200px;height:200px;border-radius:50%;
  background:radial-gradient(circle,rgba(0,194,203,.22),transparent 70%);
  margin:0 auto 32px;display:flex;align-items:center;justify-content:center;
  font-size:64px;animation:completePulse 2s ease-in-out infinite;
}
@keyframes completePulse{0%,100%{transform:scale(1);}50%{transform:scale(1.05);}}
.completion h2{font-size:clamp(28px,4vw,44px);font-weight:900;letter-spacing:-.03em;margin-bottom:12px;}
.completion p{font-size:14px;color:var(--muted2);max-width:400px;margin:0 auto 36px;line-height:1.8;}
.next-btn{
  display:inline-flex;align-items:center;gap:12px;padding:16px 32px;
  background:var(--accent);border:none;border-radius:6px;
  font-family:'Noto Sans KR',sans-serif;font-size:14px;font-weight:700;
  color:#000;cursor:pointer;text-decoration:none;transition:all .2s;
}
.next-btn:hover{background:var(--accent-bright);transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,194,203,.35);}

@keyframes fadeUp{from{opacity:0;transform:translateY(16px);}to{opacity:1;transform:translateY(0);}}
@media(max-width:768px){
  .nav{padding:0 20px;}
  .nav-tool-links{display:none;}
  .hero{padding:80px 24px 40px;}
  .steps-container{padding:40px 20px 80px;}
  .two-col,.tcar-grid,.output-grid{grid-template-columns:1fr;}
}
</style>
</head>
<body>
<div id="progress-bar" style="width:0%"></div>

<nav class="nav">
  <div class="nav-left">
    <span class="nav-badge">AX Level 1</span>
    <span class="nav-title">AntiGravity Lab</span>
  </div>
  <div id="step-dots" class="nav-steps"></div>
  <div class="nav-tool-links">
