<script>
const TOTAL_STEPS = 7;
let completedSteps = new Set();
let selectedNodeType = 'normal';
let flowNodes = [];
let selectedTaskName = '';

function startLab() {
  document.getElementById('hero').style.display = 'none';
  document.getElementById('steps-container').style.display = 'block';
  setTimeout(() => {
    const s = document.getElementById('step-1');
    s.classList.remove('locked'); s.classList.add('visible');
    updateNav(); updateProgress();
  }, 100);
  window.scrollTo({top:0,behavior:'smooth'});
}
function toggleStep(n) {
  const body = document.getElementById(`body-${n}`);
  if(body) body.classList.toggle('open');
}
function completeStep(n) {
  completedSteps.add(n);
  const card = document.getElementById(`card-${n}`);
  card.classList.remove('active'); card.classList.add('done');
  const body = document.getElementById(`body-${n}`);
  body.classList.remove('open');
  const btn = document.getElementById(`btn-${n}`);
  if(btn){btn.classList.add('done');btn.textContent='✓ 완료';}
  const connline = document.getElementById(`connline-${n}`);
  if(connline) connline.classList.add('done');
  const next = n + 1;
  const nextBlock = document.getElementById(`step-${next}`);
  if(nextBlock){
    nextBlock.classList.remove('locked'); nextBlock.classList.add('visible');
    const nextCard = document.getElementById(`card-${next}`);
    if(nextCard) nextCard.classList.add('active');
    const nextBody = document.getElementById(`body-${next}`);
    if(nextBody) nextBody.classList.add('open');
    // sync task name to flow builder
    if(next === 3 && selectedTaskName) {
      document.getElementById('flow-task-title').textContent = selectedTaskName + ' — 플로우';
    }
    setTimeout(() => { nextBlock.scrollIntoView({behavior:'smooth',block:'start'}); }, 300);
  } else if(n === TOTAL_STEPS) { showCompletion(); }
  updateNav(); updateProgress();
}
function toggleCheck(el) { el.classList.toggle('checked'); }
function copyPrompt(btn, id) {
  const el = document.getElementById(id);
  if(!el) return;
  const tmp = document.createElement('div'); tmp.innerHTML = el.innerHTML;
  const text = tmp.innerText || tmp.textContent;
  navigator.clipboard.writeText(text).then(() => {
    btn.classList.add('copied'); btn.innerHTML = '<span>복사됨</span> ✓';
    setTimeout(() => { btn.classList.remove('copied'); btn.innerHTML = '<span>복사</span> 📋'; }, 2000);
  }).catch(() => {
    const ta = document.createElement('textarea'); ta.value = text;
    document.body.appendChild(ta); ta.select(); document.execCommand('copy');
    document.body.removeChild(ta);
    btn.innerHTML = '✓'; setTimeout(() => { btn.innerHTML = '<span>복사</span> 📋'; }, 2000);
  });
}

// Task selector
function selectTask(el, name) {
  document.querySelectorAll('#task-selector .output-item').forEach(i => i.style.borderColor = 'var(--border)');
  el.style.borderColor = 'var(--accent)';
  if(name === '직접 입력') {
    document.getElementById('custom-task-area').style.display = 'block';
    document.getElementById('selected-task-display').style.display = 'none';
    document.getElementById('custom-task-input').oninput = function() {
      selectedTaskName = this.value;
      document.getElementById('task-name').textContent = this.value;
      document.getElementById('selected-task-display').style.display = this.value ? 'block' : 'none';
    };
  } else {
    document.getElementById('custom-task-area').style.display = 'none';
    selectedTaskName = name;
    document.getElementById('task-name').textContent = name;
    document.getElementById('selected-task-display').style.display = 'block';
  }
}

// Flow builder
function selectType(type) {
  selectedNodeType = type;
  ['normal','bottle','ai'].forEach(t => {
    const btn = document.getElementById(`type-${t}`);
    if(btn) btn.classList.toggle('selected', t === type);
  });
}
function addNode() {
  const input = document.getElementById('node-input');
  const text = input.value.trim();
  if(!text) return;
  flowNodes.push({text, type: selectedNodeType});
  renderFlow();
  input.value = '';
  input.focus();
}
function removeLastNode() {
  if(flowNodes.length > 0) { flowNodes.pop(); renderFlow(); }
}
function renderFlow() {
  const container = document.getElementById('flow-nodes');
  const empty = document.getElementById('flow-empty');
  const countLabel = document.getElementById('node-count-label');
  container.innerHTML = '';
  empty.style.display = flowNodes.length === 0 ? 'block' : 'none';
  flowNodes.forEach((node, i) => {
    if(i > 0) {
      const arrow = document.createElement('div');
      arrow.className = 'farrow'; arrow.textContent = '→';
      container.appendChild(arrow);
    }
    const wrap = document.createElement('div');
    wrap.className = 'flow-node';
    const fn = document.createElement('div');
    fn.className = `fnode fnode-${node.type === 'bottle' ? 'bottle' : node.type === 'ai' ? 'ai' : 'normal'}`;
    fn.textContent = node.text;
    fn.title = '클릭하면 삭제';
    fn.onclick = () => { flowNodes.splice(i,1); renderFlow(); };
    wrap.appendChild(fn);
    container.appendChild(wrap);
  });
  const min = 5; const cnt = flowNodes.length;
  countLabel.textContent = `노드: ${cnt} / 최소 ${min}개`;
  countLabel.style.color = cnt >= min ? 'var(--green)' : 'var(--muted)';
}

// TCAR generator
function generateTCAR() {
  const t = document.getElementById('tcar-t').value.trim();
  const c = document.getElementById('tcar-c').value.trim();
  const a = document.getElementById('tcar-a').value.trim();
  const r = document.getElementById('tcar-r').value.trim();
  const eff = document.getElementById('tcar-effect').value.trim();
  if(!t && !a) { alert('Trigger와 Action을 먼저 입력해주세요.'); return; }
  const preview = document.getElementById('tcar-preview');
  preview.innerHTML = `
    <div style="font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.18em;color:var(--accent);text-transform:uppercase;margin-bottom:12px;">자동화 시나리오 요약 카드</div>
    ${t ? `<div style="margin-bottom:8px;"><strong style="color:var(--accent);">🔵 Trigger</strong> ${t}</div>` : ''}
    ${c ? `<div style="margin-bottom:8px;"><strong style="color:var(--yellow);">🟡 Condition</strong> ${c}</div>` : ''}
    ${a ? `<div style="margin-bottom:8px;"><strong style="color:var(--green);">🟢 Action</strong> ${a}</div>` : ''}
    ${r ? `<div style="margin-bottom:8px;"><strong style="color:var(--purple);">🟣 Result</strong> ${r}</div>` : ''}
    ${eff ? `<div style="margin-top:12px;padding:8px 12px;background:var(--green-soft);border-radius:4px;font-size:11px;color:var(--green);">⚡ 예상 효과: ${eff}</div>` : ''}
  `;
  preview.classList.add('show');
}

function updateNav() {
  const container = document.getElementById('step-dots');
  container.innerHTML = '';
  for(let i = 1; i <= TOTAL_STEPS; i++) {
    const dot = document.createElement('div');
    dot.className = 'nav-step-dot';
    if(completedSteps.has(i)) dot.classList.add('done');
    else if(i === getActiveStep()) dot.classList.add('active');
    dot.onclick = () => { const el = document.getElementById(`step-${i}`); if(el && !el.classList.contains('locked')) el.scrollIntoView({behavior:'smooth'}); };
    container.appendChild(dot);
  }
}
function getActiveStep() { for(let i=1;i<=TOTAL_STEPS;i++){if(!completedSteps.has(i))return i;} return TOTAL_STEPS; }
function updateProgress() { document.getElementById('progress-bar').style.width = (completedSteps.size/TOTAL_STEPS*100)+'%'; }
function showCompletion() {
  document.getElementById('steps-container').style.display='none';
  const c = document.getElementById('completion'); c.classList.add('show'); c.scrollIntoView({behavior:'smooth'});
}
updateNav();
</script>
</body>
</html>
