.eyebrow{font-family:'Space Mono',monospace;font-size:10px;letter-spacing:.22em;color:var(--accent);text-transform:uppercase;display:flex;align-items:center;gap:10px;margin-bottom:20px;animation:fadeUp .8s ease both;}
.eyebrow::before{content:'';display:block;width:20px;height:1px;background:var(--accent);}
.hero-kicker{font-family:'Space Mono',monospace;font-size:11px;letter-spacing:.15em;color:var(--muted);text-transform:uppercase;margin-bottom:12px;animation:fadeUp .8s .05s ease both;}
.hero-h1{font-family:'Bebas Neue',sans-serif;font-size:clamp(68px,11vw,130px);line-height:.88;letter-spacing:.02em;color:var(--accent);animation:fadeUp .8s .1s ease both;}
.hero-h2{font-size:clamp(20px,2.8vw,34px);font-weight:900;letter-spacing:-.03em;margin-top:10px;animation:fadeUp .8s .15s ease both;}
.hero-desc{margin-top:20px;max-width:520px;font-size:14px;color:var(--muted2);line-height:1.85;animation:fadeUp .8s .2s ease both;}
.hero-concept{display:inline-flex;align-items:center;gap:10px;margin-top:24px;padding:10px 20px;background:var(--accent-soft);border:1px solid var(--accent-mid);border-radius:4px;font-size:13px;font-weight:600;animation:fadeUp .8s .25s ease both;}
.hero-meta{display:flex;gap:0;margin-top:32px;border:1px solid var(--border);border-radius:6px;overflow:hidden;width:fit-content;animation:fadeUp .8s .3s ease both;}
.meta-cell{padding:14px 24px;border-right:1px solid var(--border);}
.meta-cell:last-child{border-right:none;}
.meta-k{font-family:'Space Mono',monospace;font-size:8px;letter-spacing:.2em;color:var(--muted);text-transform:uppercase;margin-bottom:4px;}
.meta-v{font-size:15px;font-weight:800;}
.start-btn{margin-top:36px;display:inline-flex;align-items:center;gap:12px;padding:14px 28px;background:var(--accent);border:none;border-radius:5px;font-family:'Noto Sans KR',sans-serif;font-size:14px;font-weight:700;color:#fff;cursor:pointer;transition:all .2s;animation:fadeUp .8s .35s ease both;}
.start-btn:hover{background:var(--accent-bright);transform:translateY(-2px);box-shadow:0 8px 24px rgba(255,107,107,.3);}

.steps-container{max-width:900px;margin:0 auto;padding:80px 48px 120px;}
.step-block{margin-bottom:4px;opacity:0;transform:translateY(20px);transition:opacity .4s ease,transform .4s ease;pointer-events:none;}
.step-block.visible{opacity:1;transform:translateY(0);pointer-events:all;}
.step-block.locked{opacity:.25;pointer-events:none;filter:blur(1px);}
.step-connector{display:flex;justify-content:center;padding:8px 0;}
.step-connector-line{width:1px;height:32px;background:linear-gradient(to bottom,var(--border),transparent);}
.step-connector-line.done{background:linear-gradient(to bottom,var(--green),rgba(0,212,138,.1));}
.step-card{background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;transition:border-color .3s;}
.step-card.active{border-color:var(--accent-mid);}
.step-card.done{border-color:rgba(0,212,138,.25);}
.step-header{padding:24px 28px;display:flex;align-items:center;gap:16px;border-bottom:1px solid var(--border);cursor:pointer;user-select:none;}
.step-num{width:40px;height:40px;border-radius:8px;background:var(--accent-soft);border:1px solid var(--accent-mid);display:flex;align-items:center;justify-content:center;font-family:'Bebas Neue',sans-serif;font-size:20px;color:var(--accent);flex-shrink:0;transition:all .3s;}
.step-card.done .step-num{background:var(--green-soft);border-color:rgba(0,212,138,.3);color:var(--green);}
.step-num-done-icon{display:none;font-size:16px;}
.step-card.done .step-num-text{display:none;}
.step-card.done .step-num-done-icon{display:block;}
.step-header-text{flex:1;}
.step-phase{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.18em;color:var(--muted);text-transform:uppercase;margin-bottom:3px;}
.step-title{font-size:16px;font-weight:800;letter-spacing:-.01em;}
.step-badge{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.1em;padding:4px 10px;border-radius:2px;background:var(--bg);border:1px solid var(--border);color:var(--muted);white-space:nowrap;}
.step-body{padding:28px;display:none;}
.step-body.open{display:block;}
.content-block{margin-bottom:24px;}
.block-label{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.2em;color:var(--muted);text-transform:uppercase;margin-bottom:10px;display:flex;align-items:center;gap:6px;}
.block-label::before{content:'';display:block;width:12px;height:1px;background:var(--muted);}
.narrative{font-size:14px;color:var(--muted2);line-height:1.85;padding:16px 20px;background:var(--bg2);border-radius:6px;border-left:3px solid var(--accent-mid);}
.narrative strong{color:var(--text);}
.prompt-box{background:var(--bg);border:1px solid var(--accent-mid);border-radius:8px;overflow:hidden;margin-bottom:10px;}
.prompt-topbar{padding:8px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;background:var(--accent-soft);}
.prompt-topbar-left{display:flex;align-items:center;gap:8px;font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.15em;color:var(--accent);text-transform:uppercase;}
.prompt-topbar-left::before{content:'›_';opacity:.7;}
.copy-btn{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.12em;text-transform:uppercase;padding:4px 12px;border-radius:3px;background:var(--accent-soft);border:1px solid var(--accent-mid);color:var(--accent);cursor:pointer;transition:all .2s;display:flex;align-items:center;gap:6px;}
.copy-btn:hover{background:var(--accent);color:#fff;}
.copy-btn.copied{background:var(--green-soft);border-color:rgba(0,212,138,.3);color:var(--green);}
.prompt-content{padding:16px 18px;font-size:12px;line-height:1.85;color:var(--muted2);white-space:pre-line;font-family:'Space Mono',monospace;letter-spacing:.01em;}
.prompt-content .ph{color:var(--accent-bright);background:rgba(255,107,107,.12);padding:1px 5px;border-radius:3px;font-weight:700;}
.checklist{list-style:none;}
.check-item{display:flex;align-items:flex-start;gap:12px;padding:12px 0;border-bottom:1px solid var(--border);cursor:pointer;transition:opacity .2s;}
.check-item:last-child{border-bottom:none;}
.check-item.checked{opacity:.55;}
.check-box{width:20px;height:20px;border-radius:4px;border:1.5px solid var(--muted);display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:2px;transition:all .2s;}
.check-item.checked .check-box{background:var(--green);border-color:var(--green);}
.check-icon{font-size:11px;opacity:0;transition:opacity .2s;}
.check-item.checked .check-icon{opacity:1;}
.check-text{font-size:13px;line-height:1.6;transition:all .2s;}
.check-item.checked .check-text{text-decoration:line-through;color:var(--muted);}
.tip-box{padding:14px 18px;background:var(--surface2);border-radius:6px;border:1px solid rgba(255,179,71,.15);display:flex;gap:10px;font-size:13px;color:var(--muted2);line-height:1.65;}
.tip-icon{flex-shrink:0;font-size:16px;}
.output-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;}
.output-item{padding:14px 16px;background:var(--bg2);border:1px solid var(--border);border-radius:6px;display:flex;gap:10px;align-items:flex-start;}
.output-emoji{font-size:18px;flex-shrink:0;}
.output-text{font-size:12px;color:var(--muted2);line-height:1.6;}
.output-text strong{color:var(--text);display:block;font-size:13px;margin-bottom:2px;}
.complete-btn{width:100%;margin-top:24px;padding:14px 24px;border:1px solid var(--accent-mid);border-radius:6px;background:var(--accent-soft);color:var(--accent);font-family:'Noto Sans KR',sans-serif;font-size:13px;font-weight:700;cursor:pointer;transition:all .25s;display:flex;align-items:center;justify-content:center;gap:10px;letter-spacing:.02em;}
.complete-btn:hover{background:var(--accent);color:#fff;box-shadow:0 4px 20px rgba(255,107,107,.25);transform:translateY(-1px);}
.complete-btn.done{background:var(--green-soft);border-color:rgba(0,212,138,.3);color:var(--green);cursor:default;}
.lab-divider{display:flex;align-items:center;gap:16px;padding:32px 0;}
.lab-divider-line{flex:1;height:1px;background:var(--border);}
.lab-divider-text{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.2em;color:var(--muted);text-transform:uppercase;white-space:nowrap;}

/* Vibe coding concept */
.vibe-row{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;}
.vibe-card{padding:20px;background:var(--bg2);border:1px solid var(--border);border-radius:6px;transition:border-color .2s;}
.vibe-card:hover{border-color:var(--accent-mid);}
.vibe-icon{font-size:24px;margin-bottom:10px;}
.vibe-title{font-size:13px;font-weight:700;margin-bottom:5px;}
.vibe-desc{font-size:11px;color:var(--muted2);line-height:1.65;}

/* Prompt builder */
.pbuilder{background:var(--bg);border:1px solid var(--accent-mid);border-radius:8px;overflow:hidden;}
.pbuilder-bar{padding:10px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;background:var(--accent-soft);}
.pbuilder-title{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.15em;color:var(--accent);text-transform:uppercase;}
.pbuilder-body{padding:16px;}
.pb-row{display:grid;grid-template-columns:auto 1fr;gap:12px;align-items:center;margin-bottom:10px;}
.pb-label{font-family:'Space Mono',monospace;font-size:10px;letter-spacing:.1em;color:var(--muted2);white-space:nowrap;}
.pb-input{background:var(--surface);border:1px solid var(--border);border-radius:4px;padding:8px 12px;color:var(--text);font-family:'Noto Sans KR',sans-serif;font-size:12px;outline:none;transition:border-color .2s;width:100%;}
.pb-input:focus{border-color:var(--accent-mid);}
.pb-select{background:var(--surface);border:1px solid var(--border);border-radius:4px;padding:8px 12px;color:var(--text);font-family:'Noto Sans KR',sans-serif;font-size:12px;outline:none;transition:border-color .2s;width:100%;cursor:pointer;}
.pb-select:focus{border-color:var(--accent-mid);}
.pb-generate-btn{width:100%;margin-top:6px;padding:10px;background:var(--accent);border:none;border-radius:5px;color:#fff;font-family:'Noto Sans KR',sans-serif;font-size:13px;font-weight:700;cursor:pointer;transition:all .2s;}
.pb-generate-btn:hover{background:var(--accent-bright);}
.pb-result{display:none;margin-top:12px;background:var(--bg2);border:1px solid var(--border);border-radius:6px;overflow:hidden;}
.pb-result.show{display:block;}
.pb-result-bar{padding:7px 14px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;}
.pb-result-label{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.15em;color:var(--muted);text-transform:uppercase;}
.pb-result-content{padding:14px 16px;font-size:11px;font-family:'Space Mono',monospace;line-height:1.8;color:var(--muted2);white-space:pre-line;}

/* service type selector */
.svc-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;}
.svc-card{padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:6px;cursor:pointer;transition:all .2s;}
.svc-card:hover,.svc-card.selected{border-color:var(--accent);background:var(--accent-soft);}
.svc-tag{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:.12em;color:var(--accent);text-transform:uppercase;margin-bottom:6px;}
.svc-name{font-size:13px;font-weight:700;margin-bottom:4px;}
.svc-desc{font-size:11px;color:var(--muted2);line-height:1.55;}

/* team roles */
.role-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;}
.role-card{padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:6px;}
.role-name{font-size:13px;font-weight:700;margin-bottom:4px;color:var(--accent);}
.role-desc{font-size:11px;color:var(--muted2);line-height:1.6;}

/* pitch timer */
.pitch-timer{
  padding:20px;background:var(--surface2);border:1px solid var(--border);
  border-radius:8px;text-align:center;
}
.timer-display{
  font-family:'Bebas Neue',sans-serif;
  font-size:72px;letter-spacing:.05em;color:var(--accent);
  line-height:1;margin:12px 0;
}
.timer-display.warning{color:var(--orange);}
.timer-display.danger{color:#FF4444;}
.timer-controls{display:flex;gap:8px;justify-content:center;margin-top:12px;}
.timer-btn{padding:8px 20px;border-radius:4px;font-family:'Noto Sans KR',sans-serif;font-size:12px;font-weight:700;cursor:pointer;transition:all .2s;border:none;}
.timer-start{background:var(--accent);color:#fff;}
.timer-start:hover{background:var(--accent-bright);}
.timer-reset{background:var(--surface);border:1px solid var(--border);color:var(--muted2);}
.timer-reset:hover{border-color:var(--accent-mid);color:var(--text);}
.timer-label{font-family:'Space Mono',monospace;font-size:10px;color:var(--muted);letter-spacing:.12em;text-transform:uppercase;}
.timer-phase{font-size:13px;font-weight:600;color:var(--muted2);margin-top:6px;}

.completion{display:none;text-align:center;padding:80px 48px;}
.completion.show{display:block;}
.completion-glow{width:200px;height:200px;border-radius:50%;background:radial-gradient(circle,rgba(255,107,107,.2),transparent 70%);margin:0 auto 32px;display:flex;align-items:center;justify-content:center;font-size:64px;animation:completePulse 2s ease-in-out infinite;}
@keyframes completePulse{0%,100%{transform:scale(1);}50%{transform:scale(1.05);}}
.completion h2{font-size:clamp(28px,4vw,44px);font-weight:900;letter-spacing:-.03em;margin-bottom:12px;}
.completion p{font-size:14px;color:var(--muted2);max-width:440px;margin:0 auto 36px;line-height:1.8;}
.final-btn{display:inline-flex;align-items:center;gap:12px;padding:16px 32px;background:var(--accent);border:none;border-radius:6px;font-family:'Noto Sans KR',sans-serif;font-size:14px;font-weight:700;color:#fff;cursor:pointer;text-decoration:none;transition:all .2s;}
.final-btn:hover{background:var(--accent-bright);transform:translateY(-2px);box-shadow:0 8px 24px rgba(255,107,107,.35);}

@keyframes fadeUp{from{opacity:0;transform:translateY(16px);}to{opacity:1;transform:translateY(0);}}
@media(max-width:768px){
  .nav{padding:0 20px;}
  .nav-tool-links{display:none;}
  .hero{padding:80px 24px 40px;}
  .steps-container{padding:40px 20px 80px;}
  .vibe-row,.role-grid,.svc-grid,.output-grid{grid-template-columns:1fr;}
}
</style>
</head>
