</section>

<div class="steps-container" id="steps-container" style="display:none;">

  <div class="lab-divider">
    <div class="lab-divider-line"></div>
    <div class="lab-divider-text">Lab L-1 · 온보딩 체크리스트 앱 · 40분</div>
    <div class="lab-divider-line"></div>
  </div>

  <!-- STEP 1 -->
  <div class="step-block" id="step-1">
    <div class="step-card active" id="card-1">
      <div class="step-header" onclick="toggleStep(1)">
        <div class="step-num" id="num-1"><span class="step-num-text">1</span><span class="step-num-done-icon">✓</span></div>
        <div class="step-header-text">
          <div class="step-phase">개념 이해</div>
