  <div class="step-connector" id="conn-1"><div class="step-connector-line" id="connline-1"></div></div>

  <!-- STEP 2 — Account Setup -->
  <div class="step-block locked" id="step-2">
    <div class="step-card" id="card-2">
      <div class="step-header" onclick="toggleStep(2)">
        <div class="step-num" id="num-2"><span class="step-num-text">2</span><span class="step-num-done-icon">✓</span></div>
