<script>
const TOTAL_STEPS = 7;
let completedSteps = new Set();
let timerInterval = null;
let timerSeconds = 300;
let timerRunning = false;

const PHASES = [
  {at: 300, label: '준비 완료'},
  {at: 270, label: '🎯 문제 제시'},
  {at: 210, label: '💡 솔루션 소개'},
  {at: 150, label: '📱 라이브 데모'},
  {at: 90,  label: '🔮 다음 스텝'},
  {at: 30,  label: '❓ Q&A'},
  {at: 0,   label: '⏰ 시간 종료!'},
];

function startLab() {
  document.getElementById('hero').style.display = 'none';
  document.getElementById('steps-container').style.display = 'block';
  setTimeout(() => {
    const s = document.getElementById('step-1');
    s.classList.remove('locked'); s.classList.add('visible');
    updateNav(); updateProgress();
  }, 100);
  window.scrollTo({top:0,behavior:'smooth'});
}
function toggleStep(n) {
  const body = document.getElementById(`body-${n}`);
  if(body) body.classList.toggle('open');
}
function completeStep(n) {
  completedSteps.add(n);
  const card = document.getElementById(`card-${n}`); card.classList.remove('active'); card.classList.add('done');
  const body = document.getElementById(`body-${n}`); body.classList.remove('open');
  const btn = document.getElementById(`btn-${n}`); if(btn){btn.classList.add('done');btn.textContent='✓ 완료';}
  const connline = document.getElementById(`connline-${n}`); if(connline) connline.classList.add('done');
  const next = n + 1;
  const nextBlock = document.getElementById(`step-${next}`);
  if(nextBlock){
    nextBlock.classList.remove('locked'); nextBlock.classList.add('visible');
    const nc = document.getElementById(`card-${next}`); if(nc) nc.classList.add('active');
    const nb = document.getElementById(`body-${next}`); if(nb) nb.classList.add('open');
    setTimeout(() => { nextBlock.scrollIntoView({behavior:'smooth',block:'start'}); }, 300);
  } else if(n === TOTAL_STEPS) { showCompletion(); }
  updateNav(); updateProgress();
}
function toggleCheck(el) { el.classList.toggle('checked'); }
function copyPrompt(btn, id) {
  const el = document.getElementById(id); if(!el) return;
  const tmp = document.createElement('div'); tmp.innerHTML = el.innerHTML;
  const text = tmp.innerText || tmp.textContent;
  navigator.clipboard.writeText(text).then(() => {
    btn.classList.add('copied'); btn.innerHTML = '<span>복사됨</span> ✓';
    setTimeout(() => { btn.classList.remove('copied'); btn.innerHTML = '<span>복사</span> 📋'; }, 2000);
  }).catch(() => {
    const ta = document.createElement('textarea'); ta.value = text;
    document.body.appendChild(ta); ta.select(); document.execCommand('copy'); document.body.removeChild(ta);
    btn.innerHTML = '✓'; setTimeout(() => { btn.innerHTML = '<span>복사</span> 📋'; }, 2000);
  });
}

// Prompt builder
function updatePromptPreview() {}
function generatePrompt() {
  const company = document.getElementById('pb-company').value || '우리 회사';
  const target = document.getElementById('pb-target').value || '신입사원';
  const count = document.getElementById('pb-count').value;
  const color = document.getElementById('pb-color').value;
  const text = `${company}의 ${target} 온보딩 체크리스트 웹앱을 만들어줘.

기능:
- 완료해야 할 항목 ${count}개
- 각 항목 체크박스 클릭 → 완료 처리 (취소선 + 색상 변경)
- 상단에 전체 진행률 표시 (예: 7/${count} 완료)
- 완료 시 축하 메시지 + 애니메이션

디자인: ${color}
제목: "${company} 온보딩 가이드"`;
  document.getElementById('pb-result-content').textContent = text;
  document.getElementById('pb-result').classList.add('show');
}
function copyGenerated() {
  const text = document.getElementById('pb-result-content').textContent;
  const btn = document.getElementById('pb-copy-btn');
  navigator.clipboard.writeText(text).then(() => {
    btn.classList.add('copied'); btn.innerHTML = '복사됨 ✓';
    setTimeout(() => { btn.classList.remove('copied'); btn.innerHTML = '복사 📋'; }, 2000);
  });
}

// Service selector
function selectSvc(el, name) {
  document.querySelectorAll('.svc-card').forEach(c => c.classList.remove('selected'));
  el.classList.add('selected');
  document.getElementById('svc-name').textContent = name;
  document.getElementById('svc-selected-display').style.display = 'block';
}

// Pitch timer
function toggleTimer() {
  if(timerRunning) {
    clearInterval(timerInterval); timerRunning = false;
    document.getElementById('timer-start-btn').textContent = '▶ 재시작';
  } else {
    timerRunning = true;
    document.getElementById('timer-start-btn').textContent = '⏸ 일시정지';
    timerInterval = setInterval(() => {
      if(timerSeconds <= 0) {
        clearInterval(timerInterval); timerRunning = false;
        document.getElementById('timer-start-btn').textContent = '▶ 시작';
        return;
      }
      timerSeconds--;
      updateTimerDisplay();
    }, 1000);
  }
}
function resetTimer() {
  clearInterval(timerInterval); timerRunning = false;
  timerSeconds = 300; updateTimerDisplay();
  document.getElementById('timer-start-btn').textContent = '▶ 시작';
  document.getElementById('timer-phase').textContent = '준비 완료';
}
function updateTimerDisplay() {
  const m = Math.floor(timerSeconds / 60).toString().padStart(2,'0');
  const s = (timerSeconds % 60).toString().padStart(2,'0');
  const disp = document.getElementById('timer-display');
  disp.textContent = `${m}:${s}`;
  disp.className = 'timer-display';
  if(timerSeconds <= 30) disp.classList.add('danger');
  else if(timerSeconds <= 90) disp.classList.add('warning');
  // phase label
  for(let i = 0; i < PHASES.length - 1; i++) {
    if(timerSeconds <= PHASES[i].at && timerSeconds > PHASES[i+1].at) {
      document.getElementById('timer-phase').textContent = PHASES[i+1].label;
      break;
    }
  }
}

function updateNav() {
  const container = document.getElementById('step-dots'); container.innerHTML = '';
  for(let i = 1; i <= TOTAL_STEPS; i++) {
    const dot = document.createElement('div'); dot.className = 'nav-step-dot';
    if(completedSteps.has(i)) dot.classList.add('done');
    else if(i === getActiveStep()) dot.classList.add('active');
    dot.onclick = () => { const el = document.getElementById(`step-${i}`); if(el && !el.classList.contains('locked')) el.scrollIntoView({behavior:'smooth'}); };
    container.appendChild(dot);
  }
}
function getActiveStep() { for(let i=1;i<=TOTAL_STEPS;i++){if(!completedSteps.has(i))return i;} return TOTAL_STEPS; }
function updateProgress() { document.getElementById('progress-bar').style.width=(completedSteps.size/TOTAL_STEPS*100)+'%'; }
function showCompletion() {
  document.getElementById('steps-container').style.display='none';
  const c = document.getElementById('completion'); c.classList.add('show'); c.scrollIntoView({behavior:'smooth'});
}
updateNav();
</script>
</body>
</html>
